// Detecta tipo do arquivo (XML ou PDF) e normaliza a chave binária para 'arquivo'
const item = $input.first();
const binaryKeys = Object.keys(item.binary || {});

if (binaryKeys.length === 0) {
  return [{ json: { tipo: 'erro', mensagem: 'Nenhum arquivo recebido' } }];
}

const fileKey = binaryKeys[0];
const file = item.binary[fileKey];
const mimeType = (file.mimeType || '').toLowerCase();
const fileName = (file.fileName || fileKey).toLowerCase();

let tipo = 'erro';
if (mimeType.includes('xml') || fileName.endsWith('.xml')) {
  tipo = 'xml';
} else if (mimeType.includes('pdf') || fileName.endsWith('.pdf')) {
  tipo = 'pdf';
}

return [{
  json: { tipo, fileName: file.fileName || fileKey, mimeType },
  binary: { arquivo: file }
}];

// Extrai dados do DESTINATÁRIO do XML da NF-e brasileira
const item = $input.first();
const binaryData = item.binary.arquivo;
const xmlContent = Buffer.from(binaryData.data, 'base64').toString('utf-8');

function extractTag(xml, tag) {
  const match = xml.match(new RegExp('<' + tag + '[^>]*>([\\s\\S]*?)<\\/' + tag + '>'));
  return match ? match[1].replace(/<[^>]+>/g, '').trim() : '';
}

// Seção do destinatário
const destMatch = xmlContent.match(/<dest>([\s\S]*?)<\/dest>/);
const dest = destMatch ? destMatch[1] : '';

if (!dest) {
  return [{ json: { sucesso: false, mensagem: 'Seção <dest> não encontrada no XML. Verifique se o arquivo é uma NF-e válida.' } }];
}

const nome     = extractTag(dest, 'xNome');
const cnpj     = extractTag(dest, 'CNPJ');
const cpf      = extractTag(dest, 'CPF');
const cidade   = extractTag(dest, 'xMun');
const estado   = extractTag(dest, 'UF');
let telefone   = extractTag(dest, 'fone');

// Formata telefone
if (telefone) {
  const d = telefone.replace(/\D/g, '');
  if (d.length === 11)      telefone = '(' + d.slice(0,2) + ') ' + d.slice(2,7) + '-' + d.slice(7);
  else if (d.length === 10) telefone = '(' + d.slice(0,2) + ') ' + d.slice(2,6) + '-' + d.slice(6);
}

return [{
  json: {
    sucesso: true,
    nome,
    contato: nome,
    telefone,
    cidade,
    estado,
    documento: cnpj || cpf,
    tipo_documento: cnpj ? 'CNPJ' : 'CPF',
    fonte: 'xml'
  }
}];

