// Interpreta o JSON retornado pelo GPT
const item = $input.first();
const content = item.json.choices?.[0]?.message?.content || '{}';

try {
  const cleaned = content
    .replace(/```json\n?/gi, '')
    .replace(/```\n?/g, '')
    .trim();
  const data = JSON.parse(cleaned);
  return [{ json: { ...data, fonte: 'pdf', sucesso: true } }];
} catch (e) {
  return [{
    json: {
      sucesso: false,
      mensagem: 'Não foi possível interpretar a resposta da IA. Tente novamente ou use o XML da NF-e.',
      fonte: 'pdf'
    }
  }];
}
